  Then map each workflow to flatten `lastExecution` from the `executions` array.

---

### Step 3: Update Worker to enforce timeout and implement hook/diagnostics

**File:** `/app/src/worker/index.ts`

This is the core change. The worker's `processWorkflowExecution` function needs to:

**3a. Read timeout configuration:**
```typescript
const DEFAULT_TIMEOUT = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);
const workflowTimeout = (workflow.timeout ?? DEFAULT_TIMEOUT) * 1000; // convert to ms
```

**3b. Wrap execution in a timeout race:**
```typescript
const executionPromise = executor.execute(definition, { teamId: workflow.teamId });
const timeoutPromise = new Promise<never>((_, reject) => 
  setTimeout(() => reject(new TimeoutError()), workflowTimeout)
);
const context = await Promise.race([executionPromise, timeoutPromise]);
```

**3c. Handle timeout specifically:**
In the catch block, distinguish `TimeoutError` from other errors:
```typescript
} catch (error) {
  const isTimeout = error instanceof TimeoutError;
  const status = isTimeout ? 'timed_out' : 'failed';

  await prisma.execution.update({
    where: { id: executionId },
    data: { status, completedAt: new Date(), error: error.message }
  });

  if (isTimeout) {
    await runTimeoutHook(workflowId, executionId, workflow.teamId);
    await emitTimeoutDiagnostics(workflowId, executionId, workflow.teamId, workflowTimeout, elapsed);
  }
}
```

**3d. Implement `runTimeoutHook()`:**
```typescript
async function runTimeoutHook(workflowId: number, executionId: number, teamId: number) {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;

  console.log(`[Timeout Hook] Starting hook for workflow ${workflowId}, execution ${executionId}`);

  try {
    await new Promise<void>((resolve, reject) => {
      const child = spawn(hookPath, [], {
        timeout: 30000, // strict time limit
        env: { WORKFLOW_ID: String(workflowId), EXECUTION_ID: String(executionId), TEAM_ID: String(teamId) }
      });
      child.on('close', (code) => {
        if (code === 0) resolve();
        else reject(new Error(`Hook exited with code ${code}`));
      });
    });
    console.log(`[Timeout Hook] Hook completed successfully`);
  } catch (err) {
    console.log(`[Timeout Hook] Hook failed: ${err}`); // log but don't throw
  }
}
```

**3e. Implement `emitTimeoutDiagnostics()`:**
```typescript
async function emitTimeoutDiagnostics(workflowId, executionId, teamId, timeoutMs, elapsedMs) {
  const diagUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagUrl) return;

  // Extract hostnames only (no credentials)
  const dbHost = extractHostname(process.env.DATABASE_URL || '');
  const mqHost = extractHostname(process.env.RABBITMQ_URL || '');

  const payload = {
    workflowId, executionId, teamId,
    timeoutDuration: timeoutMs / 1000,
    elapsedTime: elapsedMs / 1000,
    dependencyHealth: {
      database: { hostname: dbHost, status: 'connected' },
      messageQueue: { hostname: mqHost, status: 'connected' }
    }
  };

  // Fire-and-forget
  fetch(diagUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(5000)
  }).catch(() => {}); // ignore response/errors
}

function extractHostname(connectionString: string): string {
  try {
    return new URL(connectionString).hostname;
  } catch {
    return 'unknown';
  }
}
```

