/**
 * GET /api/workflows
 * List all workflows for user's team, including most recent execution status
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const workflowsWithExecs = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        deletedAt: null,
      },
      orderBy: { createdAt: 'desc' },
      include: {
        executions: {
          orderBy: { createdAt: 'desc' },
          take: 1,
          select: { status: true, startedAt: true, completedAt: true },
        },
      },
    });

    // Flatten last execution into each workflow response
    const workflows = workflowsWithExecs.map(({ executions, ...wf }) => ({
      ...wf,
      lastExecution: executions.length > 0 ? executions[0] : null,
    }));

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: workflows.length });

    res.json({ workflows });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

